<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full d-flex">
                        <h4 class="modal-title">{{ $t('Add Tax Product Code') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>

                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema"
                            v-on:OnSubmit="onSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataServices from "@/services/DataService";
export default {
    props: {
    },
    data() {
        return {
            isLoading: false,
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Add Tax Code'),
                            name: "ItemCode",
                            value: "",
                            validationRules: { "required": true },
                        },
                    ],
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close
                }
            ],
        }
    },
    created: async function () {
    },
    methods: {
        Close: function () {
            this.$parent.AddItem = false;
        },
        onSubmit(formfields, val) {
            var vm = this;
            var jsonobj = {
                taxCode: formfields.ItemCode
            };
            var params = JSON.stringify(jsonobj);
            DataServices.SaveTaxCode(params).then((response) => {
                if (response.data[0].Status == 'Success') {
                    vm.$parent.ShowSearchData("", "TAX_CODE")
                    vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("ItemCode")]), "success", true, vm.$t("Alert"));
                    vm.Close();
                }
                else if (response.data[0].Status == 'Exist') {
                      vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('ItemCode')]), "warning", true, vm.$t("Alert"));                                
                      vm.Close();
                }
                else {
                    vm.ShowAlert(vm.$t("AddedError", [vm.$t("ItemCode")]), "failure", true, vm.$t("Alert"));
                    vm.Close();
                }
            });
        }
    }
}
</script>